const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;

interface Item {
  type: string;
}
interface QuoteStep {
  op: "quote";
  items: Item[];
}
interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

// Per spec: intermediate amounts are kept as fractions; only the final
// premium is rounded (up, in MHPCO's favour).
const applyPercentSurcharge = (base: number, percent: number): number =>
  (base * (100 + percent)) / 100;

const roundPremiumUp = (amount: number): number => Math.ceil(amount);

const quotePremium = (step: QuoteStep): number => {
  const [firstItem] = step.items;
  if (firstItem === undefined) return PROCESSING_FEE;
  const itemBase = BASE_PREMIUM[firstItem.type];
  const itemWithFirstInsurance = applyPercentSurcharge(itemBase, FIRST_INSURANCE_SURCHARGE_PERCENT);
  return roundPremiumUp(itemWithFirstInsurance + PROCESSING_FEE);
};

export const processScenario = (scenario: Scenario): unknown => {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step) }));
  return { results };
};

