  const itemsTotal = itemsBaseTotal(step.items);
  const withFirstInsurance = applyPercentSurcharge(itemsTotal, FIRST_INSURANCE_SURCHARGE_PERCENT);
  return roundPremiumUp(withFirstInsurance + PROCESSING_FEE);
};

